import { Component, h, Prop, Watch, State, Element } from '@stencil/core';
import { forwardCommonHostAttributes, twMerge } from '../../utils/utils';

export type MediaAspect = 'landscape' | 'portrait' | 'square';
export type MediaShape = 'flat' | 'round';
export type ObjectFit = 'cover' | 'contain' | 'fill' | 'none' | 'scale-down';

export type LandscapeRatio = '45:8' | '32:9' | '3:1' | '5:2' | '40:17' | '7:3' | '2:1' | '16:9' | '3:2' | '4:3' | '5:4';

export type PortraitRatio = '4:5' | '3:4' | '5:7' | '2:3' | '9:16' | '3:7' | '1:3';

@Component({
  tag: 'wdpr-media',
  shadow: true
})
export class WdprMedia {
  @Element() el: HTMLWdprMediaElement;

  /** Base/fallback image source */
  @Prop() src: string;

  /** Responsive source for small screens (eg., smart phones) */
  @Prop({ mutable: true }) smallSrc: string;
  /** Responsive sources for medium screens (e.g., tablets) */
  @Prop({ mutable: true }) mediumSrc: string;
  /** Responsive sources for large screens (e.g., desktops) */
  @Prop({ mutable: true }) largeSrc: string;

  /** Alt text */
  @Prop() alt: string = null;

  /** Placeholder (URL/base64) or CSS `url('...')` */
  @Prop() placeholder: string = null;

  /** Fade from placeholder to image on load */
  @Prop() fade: boolean = false;

  /** High-level aspect preset */
  @Prop() aspect: MediaAspect = 'landscape';

  /** For aspect="square": flat=square, round=circle */
  @Prop() shape: MediaShape = 'flat';

  /** CSS object-fit for the image */
  @Prop() objectFit: ObjectFit = 'cover';

  /** Landscape ratio preset (used only when aspect="landscape") */
  @Prop() landscapeRatio: LandscapeRatio = '16:9';

  /** Portrait ratio preset (used only when aspect="portrait") */
  @Prop() portraitRatio: PortraitRatio = '3:4';

  @State() loaded = false;

  // Normalize sources whenever one changes
  @Watch('src')
  @Watch('smallSrc')
  @Watch('mediumSrc')
  @Watch('largeSrc')
  syncSources() {
    this.smallSrc = this.smallSrc || this.src;
    this.mediumSrc = this.mediumSrc || this.src;
    this.largeSrc = this.largeSrc || this.src;
  }

  componentWillLoad() {
    this.syncSources();
  }

  // ---------- Tailwind class helpers ----------
  private landscapeAspectClassMap: Record<LandscapeRatio, string> = {
    '45:8': 'aspect-[45/8]',
    '32:9': 'aspect-[32/9]',
    '3:1': 'aspect-[3/1]',
    '5:2': 'aspect-[5/2]',
    '40:17': 'aspect-[40/17]',
    '7:3': 'aspect-[7/3]',
    '2:1': 'aspect-[2/1]',
    '16:9': 'aspect-[16/9]',
    '3:2': 'aspect-[3/2]',
    '4:3': 'aspect-[4/3]',
    '5:4': 'aspect-[5/4]'
  };

  private portraitAspectClassMap: Record<PortraitRatio, string> = {
    '4:5': 'aspect-[4/5]',
    '3:4': 'aspect-[3/4]',
    '5:7': 'aspect-[5/7]',
    '2:3': 'aspect-[2/3]',
    '9:16': 'aspect-[9/16]',
    '3:7': 'aspect-[3/7]',
    '1:3': 'aspect-[1/3]'
  };

  private get aspectClass(): string {
    if (this.aspect === 'square') return 'aspect-square';
    if (this.aspect === 'portrait') return this.portraitAspectClassMap[this.portraitRatio] || this.portraitAspectClassMap['3:4'];

    return this.landscapeAspectClassMap[this.landscapeRatio] || this.landscapeAspectClassMap['16:9'];
  }

  private get roundingClass(): string {
    return this.aspect === 'square' && this.shape === 'round' ? 'rounded-full' : 'rounded-none';
  }

  private get wrapperClass(): string {
    return twMerge('relative block w-full overflow-hidden', this.aspectClass, this.roundingClass);
  }

  private get placeholderClass(): string {
    return twMerge('absolute inset-0 w-full h-full', this.fade ? 'opacity-100 transition-opacity duration-500' : '', this.fade && this.loaded ? 'opacity-1250' : '');
  }

  private get pictureClass(): string {
    return 'absolute inset-0 block w-full h-full';
  }

  private get imgClass(): string {
    const fit =
      this.objectFit === 'contain' ?
        'object-contain' :
        this.objectFit === 'fill' ?
          'object-fill' :
          this.objectFit === 'none' ?
            'object-none' :
            this.objectFit === 'scale-down' ?
              'object-scale-down' :
              'object-cover';

    return twMerge(
      'block w-full h-full',
      fit,
      this.fade ? 'transition-opacity duration-500' : '',
      this.fade && !this.loaded ? 'opacity-000' : '',
      !this.fade || this.loaded ? 'opacity-1250' : ''
    );
  }

  private extractUrlFromCssUrl(input: string): string | null {
    const m = input?.match(/^url\((?:'|")?(.*?)(?:'|")?\)$/i);

    return m?.[1] || null;
  }

  private handleLoad = () => {
    if (this.fade) this.loaded = true;
  };

  render() {
    const urlFromCss = this.placeholder?.startsWith('url(') ? this.extractUrlFromCssUrl(this.placeholder) : null;
    const placeholderSrc = urlFromCss || this.placeholder;

    return (
      <div {...forwardCommonHostAttributes(this.el)} class={this.wrapperClass}>
        {/* Placeholder layer (as <img> to keep Tailwind-only) */}
        {placeholderSrc && <img part="placeholder" src={placeholderSrc} alt="" aria-hidden="true" class={this.placeholderClass} loading="eager" decoding="async" />}

        {/* Image layer */}
        <picture class={this.pictureClass}>
          {this.largeSrc && <source srcSet={this.largeSrc} media="(min-width: 1024px)" />}
          {this.mediumSrc && <source srcSet={this.mediumSrc} media="(min-width: 640px)" />}
          <img
            part="image"
            src={this.smallSrc || this.src}
            alt={this.alt || ''}
            loading={this.fade ? 'eager' : 'lazy'}
            decoding="async"
            onLoad={this.handleLoad}
            class={this.imgClass}
          />
        </picture>
      </div>
    );
  }
}
